import sys

def solve_one(nums):
    max_so_far = nums[0]
    max_ending = nums[0]
    start = end = temp_start = 0
    for i in range(1, len(nums)):
        if nums[i] > max_ending + nums[i]:
            max_ending = nums[i]
            temp_start = i
        else:
            max_ending += nums[i]
        if max_so_far < max_ending:
            max_so_far = max_ending
            start, end = temp_start, i
        elif max_so_far == max_ending:
            if i - temp_start > end - start:
                start, end = temp_start, i
    return ' '.join(map(str, nums[start:end+1]))

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        out_lines.append(solve_one(arr))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

